using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: the default RenderMode for ToolStrip/StatusStrip
        // changed from ManagerRenderMode to System. Restore the .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }

    public string DisplayName { get; set; }

    [Editor(typeof(MaxItemsEditor), typeof(UITypeEditor))]
    public int MaxItems { get; set; }
}

public class MaxItemsEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        ITypeDescriptorContext? context, IServiceProvider? provider, object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null) return value;

        var control = CreateEditorControl(value);

        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
        // when passed null. Guard against it.
        if (control is null) return value;

        editorService.DropDownControl(control);
        return control.Tag ?? value;
    }

    private static Control? CreateEditorControl(object? currentValue)
    {
        var listBox = new ListBox();
        listBox.Items.AddRange(new object[] { 5, 10, 25, 50 });
        listBox.Tag = currentValue;
        listBox.SelectedIndexChanged += (s, e) =>
        {
            if (s is ListBox lb && lb.SelectedItem is not null)
                lb.Tag = lb.SelectedItem;
        };
        return listBox;
    }
}

